// HUDWidgetFormProps drives the inspector form.
type HUDWidgetFormProps struct {
	MapID         int64
	Anchor        hud.Anchor
	Order         int
	Kind          hud.WidgetKind
	Fields        []configurable.FieldDescriptor
	Values        map[string]any
	Skin          int64
	Tint          uint32
	Size          hud.WidgetSize
	UIPanelAssets []HUDAssetOption
}

// ---- helpers ----------------------------------------------------------

func hudWidgetCount(l hud.Layout) int {
	n := 0
	for _, s := range l.Anchors {
		n += len(s.Widgets)
	}
	return n
}

func hudPlural(n int) string {
	if n == 1 {
		return ""
	}
	return "s"
}

// hudSortedWidgets returns widgets in order ascending. Avoids depending
// on map iteration order in the templ.
func hudSortedWidgets(in []hud.Widget) []hud.Widget {
	out := make([]hud.Widget, len(in))
	copy(out, in)
	for i := 1; i < len(out); i++ {
		j := i
		for j > 0 && out[j-1].Order > out[j].Order {
			out[j-1], out[j] = out[j], out[j-1]
			j--
		}
	}
	return out
}

// hudKindLabel returns the human-readable label for a widget kind.
// Lives in Go (not copy.json) because it's used by the picker AND
// every chip; centralizing here keeps the two in sync.
func hudKindLabel(k hud.WidgetKind) string {
	switch k {
	case hud.WidgetResourceBar:
		return "Resource bar"
	case hud.WidgetTextLabel:
		return "Text label"
	case hud.WidgetMiniClock:
		return "Mini clock"
	case hud.WidgetIconCounter:
		return "Icon + counter"
	case hud.WidgetPortrait:
		return "Portrait"
	case hud.WidgetButton:
		return "Button"
	case hud.WidgetDialogFrame:
		return "Dialog frame"
	}
	return string(k)
}

// hudWidgetSummary returns a short single-line description per widget.
// Best-effort: parses the JSON config and pulls a binding/template/label.
func hudWidgetSummary(w hud.Widget) string {
	if len(w.Config) == 0 {
		return ""
	}
	var probe map[string]any
	if err := json.Unmarshal(w.Config, &probe); err != nil {
		return "(invalid config)"
	}
	if s, ok := probe["binding"].(string); ok && s != "" {
		return s
	}
	if s, ok := probe["template"].(string); ok && s != "" {
		return s
	}
	if s, ok := probe["label"].(string); ok && s != "" {
		return s
	}
	if s, ok := probe["channel"].(string); ok && s != "" {
		return s
	}
	if s, ok := probe["action_group"].(string); ok && s != "" {
		return s
	}
	return ""
}

